	}
	sessionDir, err := a.GetSessionDir(repoRoot)
	if err != nil {
		return "", err
	}
	if err := os.MkdirAll(sessionDir, 0o750); err != nil {
		return "", fmt.Errorf("failed to create cache dir: %w", err)
	}
